using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- DI container ---
var services = new ServiceCollection();

services.AddLogging(b => b
    .AddConsole()
    .SetMinimumLevel(LogLevel.Information));

services.AddHttpClient<WebSearchTool>();

services.AddSingleton<NoteTool>(sp =>
    new NoteTool(sp.GetRequiredService<ILogger<NoteTool>>()));

services.AddChatClient(new OpenAIClient(apiKey)
        .GetChatClient(modelId)
        .AsIChatClient())
    .UseFunctionInvocation(configure: c => c.MaximumIterationsPerRequest = 10);

var sp = services.BuildServiceProvider();

// --- Build tools from tool classes ---
var webSearch = sp.GetRequiredService<WebSearchTool>();
var noteTool = sp.GetRequiredService<NoteTool>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(noteTool.AddNote),
    AIFunctionFactory.Create(noteTool.GetNotes),
};

// --- Create the research agent ---
var chatClient = sp.GetRequiredService<IChatClient>();

var agent = chatClient.AsAIAgent(
    instructions: """
        You are a research agent. When given a topic, you must:
        1. Search the web for information using the SearchWebAsync tool. Run multiple
           searches with different queries to get broad coverage.
        2. As you find important facts, save them using the AddNote tool with
           appropriate categories (e.g., 'definition', 'key-fact', 'history',
           'application', 'statistic', 'source').
        3. After gathering enough information (at least 3-5 notes), retrieve all
           your notes using the GetNotes tool.
        4. Produce a well-structured summary of your research findings, citing
           the sources where possible.

        Be thorough but concise. Focus on the most important and interesting aspects
        of the topic.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools,
    loggerFactory: sp.GetRequiredService<ILoggerFactory>());

// --- Interactive loop ---
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (powered by      ║");
Console.WriteLine("║    Microsoft Agent Framework + MEAI)      ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();
Console.WriteLine("Enter a topic to research, or 'quit' to exit.");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine("Goodbye!");
        break;
    }

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine($"Researching: {topic}");
    Console.WriteLine("This may take a moment...");
    Console.ResetColor();
    Console.WriteLine();

    try
    {
        var session = await agent.CreateSessionAsync();
        var runOptions = new ChatClientAgentRunOptions
        {
            ChatOptions = new ChatOptions
            {
                Temperature = 0f,
                MaxOutputTokens = 4096,
            },
        };

        var result = await agent.RunAsync(
            $"Please research the following topic and provide a comprehensive summary: {topic}",
            session,
            runOptions);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("═══ Research Summary ═══");
        Console.ResetColor();
        Console.WriteLine();

        // Display the final response
        foreach (var message in result.Messages)
        {
            if (message.Role == ChatRole.Assistant && message.Text is { Length: > 0 })
            {
                Console.WriteLine(message.Text);
            }
        }

        // Show collected notes
        var notes = noteTool.AllNotes;
        if (notes.Count > 0)
        {
            Console.WriteLine();
            Console.ForegroundColor = ConsoleColor.DarkGray;
            Console.WriteLine($"[{notes.Count} research note(s) collected during this session]");
            Console.ResetColor();
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine();
}

