 using System.ComponentModel;
 using System.Net.Http.Json;
 using System.Text.Json;
 using Microsoft.Extensions.Logging;

 namespace ResearchAgent.Tools;

 public sealed class WebSearchTool
 {
     private readonly HttpClient _httpClient;
     private readonly ILogger<WebSearchTool> _logger;

     public WebSearchTool(HttpClient httpClient, ILogger<WebSearchTool> logger)
     {
         _httpClient = httpClient;
         _logger = logger;
     }

     [Description("Search the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
     public async Task<string> SearchWebAsync(
         [Description("The search query to look up on the web")] string query,
         [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
     {
         maxResults = Math.Clamp(maxResults, 1, 10);
         _logger.LogInformation("Searching web for: {Query} (max {MaxResults} results)", query, maxResults);

         try
         {
             var encodedQuery = Uri.EscapeDataString(query);
             var response = await _httpClient.GetAsync(
                 $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1");

             if (!response.IsSuccessStatusCode)
             {
                 return $"Search failed with status {response.StatusCode}. Please try a different query.";
             }

             var json = await response.Content.ReadFromJsonAsync<JsonElement>();
             var results = new List<SearchResult>();

             // Extract the abstract if available
             var abstractText = json.TryGetProperty("AbstractText", out var at) ? at.GetString() : null;
             var abstractSource = json.TryGetProperty("AbstractSource", out var asrc) ? asrc.GetString() : null;
             var abstractUrl = json.TryGetProperty("AbstractURL", out var aurl) ? aurl.GetString() : null;

             if (!string.IsNullOrWhiteSpace(abstractText))
             {
                 results.Add(new SearchResult(
                     $"{abstractSource} (Abstract)",
                     abstractText,
                     abstractUrl ?? ""));
             }

             // Extract related topics
             if (json.TryGetProperty("RelatedTopics", out var topics) && topics.ValueKind == JsonValueKind.Array)
             {
                 foreach (var topic in topics.EnumerateArray())
                 {
                     if (results.Count >= maxResults)
                         break;

                     var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                     var firstUrl = topic.TryGetProperty("FirstURL", out var fu) ? fu.GetString() : null;

                     if (!string.IsNullOrWhiteSpace(text))
                     {
                         results.Add(new SearchResult(
                             text.Length > 80 ? text[..80] + "..." : text,
                             text,
                             firstUrl ?? ""));
                     }
                 }
             }

             if (results.Count == 0)
             {
                 return $"No results found for '{query}'. Try rephrasing the query or using different keywords.";
             }

             return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
         }
         catch (Exception ex)
         {
             _logger.LogError(ex, "Web search failed for query: {Query}", query);
             return $"Search error: {ex.Message}. Please try again with a different query.";
         }
     }

     private sealed record SearchResult(string Title, string Snippet, string Url);
 }

